class Solution {
public:
    long long smallestNumber(long long num) {
        if (num == 0) return 0;
        string s;
        if (num > 0) {
            s = to_string(num);
            sort(s.begin(), s.end());
            if (s[0] == '0') {
                int i = 1;
                while (i < s.size() && s[i] == '0') ++i;
                if (i < s.size()) swap(s[0], s[i]);
            }
            return stoll(s);
        } 
        else {
            s = to_string(-num);
            sort(s.begin(), s.end(), greater<char>());
            return -stoll(s);
        }
    }
};

